[DataContract]
public final class PurchInvoiceLineBusinessEventContract
{
    private VendInvoiceId   invoiceId;
    private Qty             quantity;
    private AmountCur       amount;
    private ItemId          itemId;
    private CurrencyCode    currency;
    private TaxGroup        taxCode;
    private TaxAmount       taxAmount;

}

Method.Source:
protected void new(
    VendInvoiceId   _invoiceId,
    Qty             _quantity,
    AmountCur       _amount,
    ItemId          _itemId,
    CurrencyCode    _currency,
    TaxGroup        _taxCode,
    TaxAmount       _taxAmount)
{
    invoiceId   = _invoiceId;
    quantity    = _quantity;
    amount      = _amount;
    itemId      = _itemId;
    currency    = _currency;
    taxCode     = _taxCode;
    taxAmount   = _taxAmount;
}

public static PurchInvoiceLineBusinessEventContract construct(
    VendInvoiceId   _invoiceId,
    Qty             _quantity,
    AmountCur       _amount,
    ItemId          _itemId,
    CurrencyCode    _currency,
    TaxGroup        _taxCode,
    TaxAmount       _taxAmount)
{
    return new PurchInvoiceLineBusinessEventContract(_invoiceId, _quantity, _amount, _itemId, _currency, _taxCode, _taxAmount);
}

[DataMember('Invoice No'), BusinessEventsDataMember('Invoice No')]
public VendInvoiceId parmInvoiceNo(VendInvoiceId _invoiceId = invoiceId)
{
    invoiceId = _invoiceId;
    return invoiceId;
}

[DataMember('Quantity'), BusinessEventsDataMember('Quantity')]
public Qty parmQuantity(Qty _quantity = quantity)
{
    quantity = _quantity;
    return quantity;
}

[DataMember('Amount'), BusinessEventsDataMember('Amount')]
public AmountCur parmAmount(AmountCur _amount = amount)
{
    amount = _amount;
    return amount;
}

[DataMember('Item Id'), BusinessEventsDataMember('Item Id')]
public ItemId parmItemId(ItemId _itemId = itemId)
{
    itemId = _itemId;
    return itemId;
}

[DataMember('Currency'), BusinessEventsDataMember('Currency')]
public CurrencyCode parmCurrency(CurrencyCode _currency = currency)
{
    currency = _currency;
    return currency;
}

[DataMember('Tax Code'), BusinessEventsDataMember('Tax Code')]
public TaxGroup parmTaxCode(TaxGroup _taxCode = taxCode)
{
    taxCode = _taxCode;
    return taxCode;
}

[DataMember('Tax Amount'), BusinessEventsDataMember('Tax Amount')]
public TaxAmount parmTaxAmount(TaxAmount _taxAmount = taxAmount)
{
    taxAmount = _taxAmount;
    return taxAmount;
}
